import{_ as a,c as n,o as l,ag as e}from"./chunks/framework.B-XtCDNB.js";const F=JSON.parse('{"title":"Streaming","description":"","frontmatter":{},"headers":[],"relativePath":"capabilities/streaming.md","filePath":"capabilities/streaming.md"}'),o={name:"capabilities/streaming.md"};function t(p,s,r,i,c,y){return l(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h1><p>Streaming is LinkedQL&#39;s lazy, pull-based result consumption model.</p><p>Use it when you want:</p><ul><li>row-by-row async iteration</li><li>lower peak memory usage for large result sets</li><li>a query result you can consume on demand instead of buffering all at once</li></ul><p>The API is:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> asyncIterable </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM public.users ORDER BY id</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#BABED8;"> asyncIterable) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><h2 id="what-streaming-is-and-is-not" tabindex="-1">What streaming is and is not <a class="header-anchor" href="#what-streaming-is-and-is-not" aria-label="Permalink to &quot;What streaming is and is not&quot;">​</a></h2><p>Streaming is:</p><ul><li>lazy</li><li>async-iterable</li><li>still a single query execution</li></ul><p>Streaming is not:</p><ul><li>a live query</li><li>a table-level changefeed</li><li>&quot;rows as they change over time&quot;</li></ul><p>If you need those, see:</p><ul><li><a href="/capabilities/live-queries">Live Queries</a></li><li><a href="/capabilities/changefeeds">Changefeeds</a></li></ul><h2 id="why-stream-exists" tabindex="-1">Why <code>stream()</code> exists <a class="header-anchor" href="#why-stream-exists" aria-label="Permalink to &quot;Why \`stream()\` exists&quot;">​</a></h2><p>Buffered queries are convenient:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT * FROM public.huge_table</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">length)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>But buffering every row before your code can start consuming them is not always what you want.</p><p>Streaming gives you the right trade there:</p><ul><li>less up-front materialization</li><li>earlier consumption</li><li>simpler handling of large result sets</li></ul><h2 id="basic-example" tabindex="-1">Basic example <a class="header-anchor" href="#basic-example" aria-label="Permalink to &quot;Basic example&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> rows </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, email</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#BABED8;"> rows) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">id</span><span style="color:#89DDFF;">,</span><span style="color:#BABED8;"> row</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">email</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>What this does:</p><ul><li>runs the query once</li><li>returns an async iterable</li><li>yields one row at a time to your loop</li></ul><h2 id="example-processing-a-large-export" tabindex="-1">Example: processing a large export <a class="header-anchor" href="#example-processing-a-large-export" aria-label="Permalink to &quot;Example: processing a large export&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> rows </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, created_at, total</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.orders</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#BABED8;"> rows) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  await</span><span style="color:#82AAFF;"> writeRowToExport</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><p>This is a better fit than <code>query()</code> when the output could be large and you want to process rows incrementally.</p><h2 id="streaming-inside-a-transaction" tabindex="-1">Streaming inside a transaction <a class="header-anchor" href="#streaming-inside-a-transaction" aria-label="Permalink to &quot;Streaming inside a transaction&quot;">​</a></h2><p><code>stream()</code> can participate in explicit transactions.</p><h3 id="example-with-edgeclient" tabindex="-1">Example with <code>EdgeClient</code> <a class="header-anchor" href="#example-with-edgeclient" aria-label="Permalink to &quot;Example with \`EdgeClient\`&quot;">​</a></h3><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> edge</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">transaction</span><span style="color:#BABED8;">(</span><span style="color:#C792EA;">async</span><span style="color:#89DDFF;"> (</span><span style="color:#BABED8;font-style:italic;">tx</span><span style="color:#89DDFF;">)</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#C792EA;">  const</span><span style="color:#BABED8;"> rows</span><span style="color:#89DDFF;"> =</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> edge</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#F07178;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">    SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">    FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">    ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">  \`</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> tx</span><span style="color:#89DDFF;"> }</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#F07178;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row</span><span style="color:#89DDFF;"> of</span><span style="color:#BABED8;"> rows</span><span style="color:#F07178;">) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">    console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">  }</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>The same idea applies across runtimes:</p><ul><li>open a transaction</li><li>pass <code>tx</code></li><li>consume rows lazily</li></ul><h2 id="runtime-notes" tabindex="-1">Runtime notes <a class="header-anchor" href="#runtime-notes" aria-label="Permalink to &quot;Runtime notes&quot;">​</a></h2><h3 id="mainstream-db-clients" tabindex="-1">Mainstream DB clients <a class="header-anchor" href="#mainstream-db-clients" aria-label="Permalink to &quot;Mainstream DB clients&quot;">​</a></h3><p>For <code>PGClient</code>, <code>MySQLClient</code>, and <code>MariaDBClient</code>, streaming maps to the underlying client/runtime&#39;s stream-capable path.</p><h3 id="edgeclient" tabindex="-1">EdgeClient <a class="header-anchor" href="#edgeclient" aria-label="Permalink to &quot;EdgeClient&quot;">​</a></h3><p><code>EdgeClient</code> can stream over:</p><ul><li>HTTP</li><li>worker ports</li></ul><p>Depending on transport settings, rows may arrive:</p><ul><li>over a message port</li><li>as a streamed HTTP body such as NDJSON</li></ul><p>The application-facing shape is still the same async iterable.</p><h3 id="flashql" tabindex="-1">FlashQL <a class="header-anchor" href="#flashql" aria-label="Permalink to &quot;FlashQL&quot;">​</a></h3><p>In FlashQL, <code>stream()</code> gives you lazy iteration over the local engine&#39;s query result.</p><p>That makes it useful for:</p><ul><li>local analytical scans</li><li>browser/worker exports</li><li>large local result sets where full buffering is unnecessary</li></ul><h2 id="related-docs" tabindex="-1">Related docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related docs&quot;">​</a></h2><ul><li><a href="/docs/query-api">Query Interface</a></li><li><a href="/capabilities/live-queries">Live Queries</a></li><li><a href="/capabilities/changefeeds">Changefeeds</a></li></ul>`,47)])])}const d=a(o,[["render",t]]);export{F as __pageData,d as default};
